    type nonrec t =
      {
      s3Uri: S3Uri.t
        [@ocaml.doc
          "The URI of the Amazon S3 prefix Amazon SageMaker downloads data required to run a processing job."];
      localPath: ProcessingLocalPath.t option
        [@ocaml.doc
          "The local path in your container where you want Amazon SageMaker to write input data to. LocalPath is an absolute path to the input data and must begin with /opt/ml/processing/. LocalPath is a required parameter when AppManaged is False (default)."];
      s3DataType: ProcessingS3DataType.t
        [@ocaml.doc
          "Whether you use an S3Prefix or a ManifestFile for the data type. If you choose S3Prefix, S3Uri identifies a key name prefix. Amazon SageMaker uses all objects with the specified key name prefix for the processing job. If you choose ManifestFile, S3Uri identifies an object that is a manifest file containing a list of object keys that you want Amazon SageMaker to use for the processing job."];
      s3InputMode: ProcessingS3InputMode.t option
        [@ocaml.doc
          "Whether to use File or Pipe input mode. In File mode, Amazon SageMaker copies the data from the input source onto the local ML storage volume before starting your processing container. This is the most commonly used input mode. In Pipe mode, Amazon SageMaker streams input data from the source directly to your processing container into named pipes without using the ML storage volume."];
      s3DataDistributionType: ProcessingS3DataDistributionType.t option
        [@ocaml.doc
          "Whether to distribute the data from Amazon S3 to all processing instances with FullyReplicated, or whether the data from Amazon S3 is sharded by Amazon S3 key, downloading one shard of data to each processing instance."];
      s3CompressionType: ProcessingS3CompressionType.t option
        [@ocaml.doc
          "Whether to GZIP-decompress the data in Amazon S3 as it is streamed into the processing container. Gzip can only be used when Pipe mode is specified as the S3InputMode. In Pipe mode, Amazon SageMaker streams input data from the source directly to your container without using the EBS volume."]}
    let context_ = "ProcessingS3Input"
    let make ?localPath =
      fun ?s3InputMode ->
        fun ?s3DataDistributionType ->
          fun ?s3CompressionType ->
            fun ~s3Uri ->
              fun ~s3DataType ->
                fun () ->
                  {
                    localPath;
                    s3InputMode;
                    s3DataDistributionType;
                    s3CompressionType;
                    s3Uri;
                    s3DataType
                  }
    let to_value x =
      structure_to_value
        [("S3Uri", (Some (S3Uri.to_value x.s3Uri)));
        ("LocalPath",
          (Option.map x.localPath ~f:ProcessingLocalPath.to_value));
        ("S3DataType", (Some (ProcessingS3DataType.to_value x.s3DataType)));
        ("S3InputMode",
          (Option.map x.s3InputMode ~f:ProcessingS3InputMode.to_value));
        ("S3DataDistributionType",
          (Option.map x.s3DataDistributionType
             ~f:ProcessingS3DataDistributionType.to_value));
        ("S3CompressionType",
          (Option.map x.s3CompressionType
             ~f:ProcessingS3CompressionType.to_value))]
    let to_query v = to_query to_value v
    let of_xml xml_arg0 =
      let s3CompressionType =
        (Option.map ~f:ProcessingS3CompressionType.of_xml)
          (Xml.child xml_arg0 "S3CompressionType") in
      let s3DataDistributionType =
        (Option.map ~f:ProcessingS3DataDistributionType.of_xml)
          (Xml.child xml_arg0 "S3DataDistributionType") in
      let s3InputMode =
        (Option.map ~f:ProcessingS3InputMode.of_xml)
          (Xml.child xml_arg0 "S3InputMode") in
      let s3DataType =
        ProcessingS3DataType.of_xml
          (Xml.child_exn ~context:context_ xml_arg0 "S3DataType") in
      let localPath =
        (Option.map ~f:ProcessingLocalPath.of_xml)
          (Xml.child xml_arg0 "LocalPath") in
      let s3Uri =
        S3Uri.of_xml (Xml.child_exn ~context:context_ xml_arg0 "S3Uri") in
      make ?s3CompressionType ?s3DataDistributionType ?s3InputMode
        ~s3DataType ?localPath ~s3Uri ()
    let of_string s = of_xml (Awso.Xml.parse_response s)[@@warning "-32"]
    let of_json json__ =
      let s3CompressionType =
        field_map json__ "S3CompressionType"
          ProcessingS3CompressionType.of_json in
      let s3DataDistributionType =
        field_map json__ "S3DataDistributionType"
          ProcessingS3DataDistributionType.of_json in
      let s3InputMode =
        field_map json__ "S3InputMode" ProcessingS3InputMode.of_json in
      let s3DataType =
        field_map_exn json__ "S3DataType" ProcessingS3DataType.of_json in
      let localPath =
        field_map json__ "LocalPath" ProcessingLocalPath.of_json in
      let s3Uri = field_map_exn json__ "S3Uri" S3Uri.of_json in
      make ?s3CompressionType ?s3DataDistributionType ?s3InputMode
        ~s3DataType ?localPath ~s3Uri ()
    let to_json v = composed_to_json to_value v
  end[@@ocaml.doc
       "Configuration for downloading input data from Amazon S3 into the processing container."]
