module DatasetDefinition =
  struct
    type nonrec t =
      {
      athenaDatasetDefinition: AthenaDatasetDefinition.t option ;
      redshiftDatasetDefinition: RedshiftDatasetDefinition.t option ;
      localPath: ProcessingLocalPath.t option
        [@ocaml.doc
          "The local path where you want Amazon SageMaker to download the Dataset Definition inputs to run a processing job. LocalPath is an absolute path to the input data. This is a required parameter when AppManaged is False (default)."];
      dataDistributionType: DataDistributionType.t option
        [@ocaml.doc
          "Whether the generated dataset is FullyReplicated or ShardedByS3Key (default)."];
      inputMode: InputMode.t option
        [@ocaml.doc
          "Whether to use File or Pipe input mode. In File (default) mode, Amazon SageMaker copies the data from the input source onto the local Amazon Elastic Block Store (Amazon EBS) volumes before starting your training algorithm. This is the most commonly used input mode. In Pipe mode, Amazon SageMaker streams input data from the source directly to your algorithm without using the EBS volume."]}
    let make ?athenaDatasetDefinition =
      fun ?redshiftDatasetDefinition ->
        fun ?localPath ->
          fun ?dataDistributionType ->
            fun ?inputMode ->
              fun () ->
                {
                  athenaDatasetDefinition;
                  redshiftDatasetDefinition;
                  localPath;
                  dataDistributionType;
                  inputMode
                }
    let to_value x =
      structure_to_value
        [("AthenaDatasetDefinition",
           (Option.map x.athenaDatasetDefinition
              ~f:AthenaDatasetDefinition.to_value));
        ("RedshiftDatasetDefinition",
          (Option.map x.redshiftDatasetDefinition
             ~f:RedshiftDatasetDefinition.to_value));
        ("LocalPath",
          (Option.map x.localPath ~f:ProcessingLocalPath.to_value));
        ("DataDistributionType",
          (Option.map x.dataDistributionType ~f:DataDistributionType.to_value));
        ("InputMode", (Option.map x.inputMode ~f:InputMode.to_value))]
    let to_query v = to_query to_value v
    let of_xml xml_arg0 =
      let inputMode =
        (Option.map ~f:InputMode.of_xml) (Xml.child xml_arg0 "InputMode") in
      let dataDistributionType =
        (Option.map ~f:DataDistributionType.of_xml)
          (Xml.child xml_arg0 "DataDistributionType") in
      let localPath =
        (Option.map ~f:ProcessingLocalPath.of_xml)
          (Xml.child xml_arg0 "LocalPath") in
      let redshiftDatasetDefinition =
        (Option.map ~f:RedshiftDatasetDefinition.of_xml)
          (Xml.child xml_arg0 "RedshiftDatasetDefinition") in
      let athenaDatasetDefinition =
        (Option.map ~f:AthenaDatasetDefinition.of_xml)
          (Xml.child xml_arg0 "AthenaDatasetDefinition") in
      make ?inputMode ?dataDistributionType ?localPath
        ?redshiftDatasetDefinition ?athenaDatasetDefinition ()
    let of_string s = of_xml (Awso.Xml.parse_response s)[@@warning "-32"]
    let of_json json__ =
      let inputMode = field_map json__ "InputMode" InputMode.of_json in
      let dataDistributionType =
        field_map json__ "DataDistributionType" DataDistributionType.of_json in
      let localPath =
        field_map json__ "LocalPath" ProcessingLocalPath.of_json in
      let redshiftDatasetDefinition =
        field_map json__ "RedshiftDatasetDefinition"
          RedshiftDatasetDefinition.of_json in
      let athenaDatasetDefinition =
        field_map json__ "AthenaDatasetDefinition"
          AthenaDatasetDefinition.of_json in
      make ?inputMode ?dataDistributionType ?localPath
        ?redshiftDatasetDefinition ?athenaDatasetDefinition ()
    let to_json v = composed_to_json to_value v
  end[@@ocaml.doc
       "Configuration for Dataset Definition inputs. The Dataset Definition input must specify exactly one of either AthenaDatasetDefinition or RedshiftDatasetDefinition types."]
module ProcessingInput =
