        ("AppManaged", (Option.map x.appManaged ~f:AppManaged.to_value));
        ("S3Input", (Option.map x.s3Input ~f:ProcessingS3Input.to_value));
        ("DatasetDefinition",
          (Option.map x.datasetDefinition ~f:DatasetDefinition.to_value))]
    let to_query v = to_query to_value v
    let of_xml xml_arg0 =
      let datasetDefinition =
        (Option.map ~f:DatasetDefinition.of_xml)
          (Xml.child xml_arg0 "DatasetDefinition") in
      let s3Input =
        (Option.map ~f:ProcessingS3Input.of_xml)
          (Xml.child xml_arg0 "S3Input") in
      let appManaged =
        (Option.map ~f:AppManaged.of_xml) (Xml.child xml_arg0 "AppManaged") in
      let inputName =
        String_.of_xml (Xml.child_exn ~context:context_ xml_arg0 "InputName") in
      make ?datasetDefinition ?s3Input ?appManaged ~inputName ()
    let of_string s = of_xml (Awso.Xml.parse_response s)[@@warning "-32"]
    let of_json json__ =
      let datasetDefinition =
        field_map json__ "DatasetDefinition" DatasetDefinition.of_json in
      let s3Input = field_map json__ "S3Input" ProcessingS3Input.of_json in
      let appManaged = field_map json__ "AppManaged" AppManaged.of_json in
      let inputName = field_map_exn json__ "InputName" String_.of_json in
      make ?datasetDefinition ?s3Input ?appManaged ~inputName ()
    let to_json v = composed_to_json to_value v
  end[@@ocaml.doc
       "The inputs for a processing job. The processing input must specify exactly one of either S3Input or DatasetDefinition types."]
module ProcessingInputs =
  struct
    type nonrec t = ProcessingInput.t list
    let make i =
      let open Result in
        ok_or_failwith
          ((check_list_max i ~max:10) >>= (fun () -> check_list_min i ~min:0));
        i
    let of_string _ =
      failwithf "of_string is not implemented for List_shape objects" ()
      [@@warning "-32"]
    let to_value xs =
      (xs |> (List.map ~f:ProcessingInput.to_value)) |> (fun x -> `List x)
    let to_query v = to_query to_value v
    let to_header _ =
      failwithf "to_header is not implemented for List_shape objects" ()
    let of_xml x =
      make
        (List.map
           ((Xml.all_children x) |>
              (List.filter
                 ~f:(function
                     | `Data s ->
                         (match Stdlib.String.trim s with
                          | "" -> false
                          | _ -> true)
                     | _ -> true))) ~f:ProcessingInput.of_xml)
    let of_json j =
      list_of_json ~kind:"ProcessingInputs" ~of_json:ProcessingInput.of_json
        j
    let to_json v = composed_to_json to_value v
  end
module ProcessingEnvironmentMap =
  struct
    type nonrec t =
      (ProcessingEnvironmentKey.t * ProcessingEnvironmentValue.t) list
    let make i =
      let open Result in
        ok_or_failwith
          ((check_list_max i ~max:100) >>=
             (fun () -> check_list_min i ~min:0));
        i
    let of_header xs =
      make
        (List.filter_map xs
           ~f:(fun (k, v) ->
                 (Base.String.chop_prefix k ~prefix:"x-amz-meta-") |>
                   (Option.map
                      ~f:(fun chopped ->
                            ((ProcessingEnvironmentKey.of_string chopped),
                              (ProcessingEnvironmentValue.of_string v))))))
    let to_value xs =
      (xs |>
         (List.map
            ~f:(fun (x, y) ->
                  (ProcessingEnvironmentKey.to_value x) |>
                    (fun x ->
                       (ProcessingEnvironmentValue.to_value y) |>
                         (fun y -> (x, y))))))
        |> (fun x -> `Map x)
    let to_query v = to_query to_value v
    let to_header _ =
      failwithf "to_header is not implemented for Map_shape objects" ()
    let of_xml _ =
      failwith "of_xml_converter_of_shape: Map_shape case not implemented"
    let of_json j =
      object_of_json ~key_of_string:ProcessingEnvironmentKey.of_string
        ~of_json:ProcessingEnvironmentValue.of_json j
    let to_json v = composed_to_json to_value v
  end
module ExperimentConfig =
  struct
