module CreateProjectOutput =
  struct
    type nonrec t =
      {
      projectArn: ProjectArn.t option
        [@ocaml.doc "The Amazon Resource Name (ARN) of the project."];
      projectId: ProjectId.t option [@ocaml.doc "The ID of the new project."]}
    type nonrec error =
      [ `ResourceLimitExceeded of ResourceLimitExceeded.t 
      | `Unknown_operation_error of (string * string option) ]
    let make ?projectArn =
      fun ?projectId -> fun () -> { projectArn; projectId }
    let error_of_json name json =
      match name with
      | "ResourceLimitExceeded" ->
          `ResourceLimitExceeded (ResourceLimitExceeded.of_json json)
      | name ->
          `Unknown_operation_error
            (name, (Some (Yojson.Safe.to_string json)))
    let error_of_xml name xml =
      match name with
      | "ResourceLimitExceeded" ->
          `ResourceLimitExceeded (ResourceLimitExceeded.of_xml xml)
      | name ->
          `Unknown_operation_error (name, (Some (Awso.Xml.to_string xml)))
    let error_to_json : error -> Yojson.Safe.t =
      function
      | `ResourceLimitExceeded e ->
          `Assoc
            [("error", (`String "ResourceLimitExceeded"));
            ("details", (ResourceLimitExceeded.to_json e))]
      | `Unknown_operation_error (code, msg) ->
          `Assoc (("error", (`String code)) ::
            ((match msg with
              | None -> []
              | Some m -> [("message", (`String m))])))
    let to_value x =
      structure_to_value
        [("ProjectArn", (Option.map x.projectArn ~f:ProjectArn.to_value));
        ("ProjectId", (Option.map x.projectId ~f:ProjectId.to_value))]
    let to_query v = to_query to_value v
    let of_xml xml_arg0 =
      let projectId =
        (Option.map ~f:ProjectId.of_xml) (Xml.child xml_arg0 "ProjectId") in
      let projectArn =
        (Option.map ~f:ProjectArn.of_xml) (Xml.child xml_arg0 "ProjectArn") in
      make ?projectId ?projectArn ()
    let of_string s = of_xml (Awso.Xml.parse_response s)[@@warning "-32"]
    let of_json json__ =
      let projectId = field_map json__ "ProjectId" ProjectId.of_json in
      let projectArn = field_map json__ "ProjectArn" ProjectArn.of_json in
      make ?projectId ?projectArn ()
    let to_json v = composed_to_json to_value v
  end[@@ocaml.doc
