      | Completed -> "Completed"
      | Failed -> "Failed"
      | Stopping -> "Stopping"
      | Stopped -> "Stopped"
      | Non_static_id s -> s
    let of_string =
      function
      | "InProgress" -> InProgress
      | "Completed" -> Completed
      | "Failed" -> Failed
      | "Stopping" -> Stopping
      | "Stopped" -> Stopped
