module Operator =
  struct
    type nonrec t =
      | Equals 
      | NotEquals 
      | GreaterThan 
      | GreaterThanOrEqualTo 
      | LessThan 
      | LessThanOrEqualTo 
      | Contains 
      | Exists 
      | NotExists 
      | In 
      | Non_static_id of string 
    let make i = i
    let to_string =
      function
      | Equals -> "Equals"
      | NotEquals -> "NotEquals"
      | GreaterThan -> "GreaterThan"
      | GreaterThanOrEqualTo -> "GreaterThanOrEqualTo"
      | LessThan -> "LessThan"
      | LessThanOrEqualTo -> "LessThanOrEqualTo"
      | Contains -> "Contains"
      | Exists -> "Exists"
      | NotExists -> "NotExists"
      | In -> "In"
      | Non_static_id s -> s
    let of_string =
      function
      | "Equals" -> Equals
      | "NotEquals" -> NotEquals
      | "GreaterThan" -> GreaterThan
      | "GreaterThanOrEqualTo" -> GreaterThanOrEqualTo
      | "LessThan" -> LessThan
      | "LessThanOrEqualTo" -> LessThanOrEqualTo
      | "Contains" -> Contains
      | "Exists" -> Exists
      | "NotExists" -> NotExists
      | "In" -> In
      | x -> Non_static_id x
    let to_value x = `Enum (to_string x)
    let to_query v = to_query to_value v
    let to_header x = to_string x
    let of_xml xml_arg0 =
      of_string (string_of_xml ~kind:"enumeration Operator" xml_arg0)
