module RetryPipelineExecutionResponse =
  struct
    type nonrec t =
      {
      pipelineExecutionArn: PipelineExecutionArn.t option
        [@ocaml.doc
          "The Amazon Resource Name (ARN) of the pipeline execution."]}
    type nonrec error =
      [ `ConflictException of ConflictException.t 
      | `ResourceLimitExceeded of ResourceLimitExceeded.t 
      | `ResourceNotFound of ResourceNotFound.t 
      | `Unknown_operation_error of (string * string option) ]
    let make ?pipelineExecutionArn = fun () -> { pipelineExecutionArn }
    let error_of_json name json =
      match name with
      | "ConflictException" ->
          `ConflictException (ConflictException.of_json json)
      | "ResourceLimitExceeded" ->
          `ResourceLimitExceeded (ResourceLimitExceeded.of_json json)
      | "ResourceNotFound" ->
          `ResourceNotFound (ResourceNotFound.of_json json)
      | name ->
          `Unknown_operation_error
            (name, (Some (Yojson.Safe.to_string json)))
    let error_of_xml name xml =
      match name with
      | "ConflictException" ->
          `ConflictException (ConflictException.of_xml xml)
      | "ResourceLimitExceeded" ->
          `ResourceLimitExceeded (ResourceLimitExceeded.of_xml xml)
      | "ResourceNotFound" -> `ResourceNotFound (ResourceNotFound.of_xml xml)
      | name ->
          `Unknown_operation_error (name, (Some (Awso.Xml.to_string xml)))
    let error_to_json : error -> Yojson.Safe.t =
      function
      | `ConflictException e ->
          `Assoc
            [("error", (`String "ConflictException"));
            ("details", (ConflictException.to_json e))]
      | `ResourceLimitExceeded e ->
          `Assoc
            [("error", (`String "ResourceLimitExceeded"));
            ("details", (ResourceLimitExceeded.to_json e))]
      | `ResourceNotFound e ->
          `Assoc
            [("error", (`String "ResourceNotFound"));
            ("details", (ResourceNotFound.to_json e))]
      | `Unknown_operation_error (code, msg) ->
          `Assoc (("error", (`String code)) ::
            ((match msg with
              | None -> []
              | Some m -> [("message", (`String m))])))
    let to_value x =
      structure_to_value
        [("PipelineExecutionArn",
           (Option.map x.pipelineExecutionArn
              ~f:PipelineExecutionArn.to_value))]
    let to_query v = to_query to_value v
    let of_xml xml_arg0 =
      let pipelineExecutionArn =
        (Option.map ~f:PipelineExecutionArn.of_xml)
          (Xml.child xml_arg0 "PipelineExecutionArn") in
      make ?pipelineExecutionArn ()
    let of_string s = of_xml (Awso.Xml.parse_response s)[@@warning "-32"]
    let of_json json__ =
      let pipelineExecutionArn =
        field_map json__ "PipelineExecutionArn" PipelineExecutionArn.of_json in
      make ?pipelineExecutionArn ()
    let to_json v = composed_to_json to_value v
  end[@@ocaml.doc "Retry the execution of the pipeline."]
